#include <bits/stdc++.h>
using namespace std;

const int N=35;

int t,n,st[N],en[N],a[N];

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d",&st[i]);
            a[i]=0;
        }
        for(int i=1;i<=n;i++){
            scanf("%d",&en[i]);
            a[i]|=((st[i]^en[i])<<n);
            a[i]|=(1<<i-1);
        }
        int x,y,ans=1;
        while(scanf("%d%d",&x,&y),x)
            a[y]|=(1<<x-1);
        for(int i=1;i<=n;i++){
            if(a[i]==(1<<n)){
                ans=0;
                break;
            }
            for(int j=1;j<=n;j++)
                if(a[j]&(1<<i-1) && (!(a[j]&(1<<j-1)) || j>=i)){
                    swap(a[j],a[i]);
                    break;
                }
            if(!(a[i]&(1<<i-1)))
                ans*=2;
            else{
                for(int j=1;j<=n;j++)
                    if(a[j]&(1<<i-1) && i!=j)
                        a[j]^=a[i];
            }
        }
        for(int i=1;i<=n;i++)
            if(a[i]==(1<<n)){
                ans=0;
                break;
            }
        if(!ans)
            puts("Oh,it's impossible~!!");
        else
            printf("%d\n",ans);
    }
    return 0;
}
